1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	function basePremium(item: any): number {
23	  return BASE_PREMIUMS[item.type] ?? 0;
24	}
25	
26	const COMPONENT_TYPES = ["rune", "moonstone"];
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	export function claimOffice(input: any): unknown {
31	  const results = [];
32	  for (const step of input.steps) {
33	    validateItemTypes(step.items);
34	    let premium = PROCESSING_FEE;
35	
36	    const components = step.items.filter((i: any) => COMPONENT_TYPES.includes(i.type));
37	    const nonComponents = step.items.filter((i: any) => !COMPONENT_TYPES.includes(i.type));
38	
39	    for (const item of nonComponents) {
40	      premium += basePremium(item);
41	    }
42	
43	    if (components.length === BLOCK_SIZE && components.every((c: any) => c.type === components[0].type)) {
44	      premium += BLOCK_PREMIUM;
45	    } else {
46	      for (const item of components) {
47	        premium += basePremium(item);
48	      }
49	    }
50	
51	    results.push({ premium });
52	  }
53	  return { results };
54	}
